# Simplified policy enforcement pipeline
from dataclasses import dataclass
from enum import Enum

class Outcome(Enum):
    ALLOW   = 'allow'
    BLOCK   = 'block'
    REWRITE = 'rewrite'
    ESCALATE = 'escalate'

@dataclass
class PolicyDecision:
    outcome: Outcome
    reason: str
    policy_clause: str  # which clause was triggered

class PolicyEnforcer:
    def __init__(self, hardcoded_prohibitions, softcoded_defaults, operator_config):
        self.hardcoded = hardcoded_prohibitions
        self.softcoded = softcoded_defaults
        self.operator  = operator_config

    def check_input(self, text: str) -> PolicyDecision:
        # Hardcoded: never overridden
        for rule in self.hardcoded:
            if rule.matches(text):
                return PolicyDecision(Outcome.BLOCK, rule.description, rule.id)
        # Operator scope restriction
        if self.operator.get('topic_restriction'):
            if not self.operator['topic_restriction'].is_relevant(text):
                return PolicyDecision(Outcome.BLOCK, 'Off-topic for this deployment', 'operator.scope')
        return PolicyDecision(Outcome.ALLOW, 'Passed all input checks', 'none')

    def check_output(self, text: str, user_context: dict) -> PolicyDecision:
        for rule in self.softcoded:
            if rule.matches(text) and not rule.is_unlocked(user_context):
                return PolicyDecision(Outcome.BLOCK, rule.description, rule.id)
        return PolicyDecision(Outcome.ALLOW, 'Passed all output checks', 'none')

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum

class Severity(Enum):
    P0 = 'P0'  # immediate physical harm / CSAM
    P1 = 'P1'  # serious policy violation
    P2 = 'P2'  # borderline / investigation needed

SLA_MINUTES = {Severity.P0: 15, Severity.P1: 240, Severity.P2: 1440}

@dataclass
class PolicyIncident:
    incident_id: str
    severity: Severity
    description: str
    account_id: str
    content_hash: str  # hash of violating content (never store raw)
    detected_at: datetime = field(default_factory=datetime.utcnow)
    resolved_at: datetime | None = None
    resolution: str = ''

    @property
    def sla_deadline(self) -> datetime:
        from datetime import timedelta
        return self.detected_at + timedelta(minutes=SLA_MINUTES[self.severity])

    @property
    def sla_breached(self) -> bool:
        return datetime.utcnow() > self.sla_deadline and self.resolved_at is None

    def resolve(self, resolution: str) -> None:
        self.resolved_at = datetime.utcnow()
        self.resolution = resolution

from dataclasses import dataclass
from typing import Callable

@dataclass
class PolicyAuditResult:
    total_reviewed: int
    true_positives:  int  # blocked and genuinely violating
    false_positives: int  # blocked but not actually violating
    false_negatives: int  # not blocked but should have been
    true_negatives:  int  # allowed and genuinely fine

    @property
    def precision(self) -> float:
        denom = self.true_positives + self.false_positives
        return self.true_positives / denom if denom else 0.0

    @property
    def recall(self) -> float:
        denom = self.true_positives + self.false_negatives
        return self.true_positives / denom if denom else 0.0

    @property
    def f1(self) -> float:
        p, r = self.precision, self.recall
        return 2 * p * r / (p + r) if (p + r) else 0.0

def audit_policy(
    sample: list[dict],  # [{text, is_violation, was_blocked}]
) -> PolicyAuditResult:
    tp = sum(1 for x in sample if x['is_violation'] and x['was_blocked'])
    fp = sum(1 for x in sample if not x['is_violation'] and x['was_blocked'])
    fn = sum(1 for x in sample if x['is_violation'] and not x['was_blocked'])
    tn = sum(1 for x in sample if not x['is_violation'] and not x['was_blocked'])
    return PolicyAuditResult(len(sample), tp, fp, fn, tn)
